209	// RunCompareViaService is the production replacement for Runner.RunCompare.
210	// It resolves prompts from inline text or PromptFile and drives each arm
211	// through the agent service (RunViaService).
212	func RunCompareViaService(ctx context.Context, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
213		run := func(runOpts RunOptions) (*Result, error) {
214			return RunViaService(ctx, workDir, runOpts)
215		}
216		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
217	}
