244	func runCompareArmWith(run RunFunc, opts CompareOptions, armIdx int, harnessName, baseDir, prompt, worktreePath string) ComparisonArm {
245		label := harnessName
246		if l, ok := opts.ArmLabels[armIdx]; ok {
247			label = l
248		}
249		arm := ComparisonArm{Harness: label}
250	
251		workDir := baseDir
252		if worktreePath != "" {
253			workDir = worktreePath
254		}
255	
256		model := opts.Model
257		if m, ok := opts.ArmModels[armIdx]; ok {
258			model = m
259		}
260	
261		runOpts := RunOptions{
262			Harness:     harnessName,
263			Prompt:      prompt,
264			Model:       model,
265			Effort:      opts.Effort,
266			Timeout:     opts.Timeout,
267			WorkDir:     workDir,
268			Permissions: opts.Permissions,
269			Correlation: opts.Correlation,
270		}
271	
272		result, err := run(runOpts)
273		if err != nil {
274			arm.ExitCode = 1
275			arm.Error = err.Error()
276		} else {
277			arm.Model = result.Model
278			arm.Output = result.Output
279			arm.ToolCalls = result.ToolCalls
280			arm.Tokens = result.Tokens
281			arm.InputTokens = result.InputTokens
282			arm.OutputTokens = result.OutputTokens
283			arm.CostUSD = result.CostUSD
284			arm.DurationMS = result.DurationMS
285			arm.ExitCode = result.ExitCode
286			arm.Error = result.Error
287		}
288	
289		if worktreePath != "" {
290			arm.Diff = captureGitDiff(worktreePath)
291		}
292	
293		if opts.PostRun != "" && workDir != "" {
294			out, ok := runPostCommand(workDir, opts.PostRun)
295			arm.PostRunOut = out
296			arm.PostRunOK = &ok
297		}
298	
299		return arm
300	}
