302	func createCompareWorktree(workDir, compareID, harnessName string) (string, error) {
303		gitRoot, err := resolveGitRoot(workDir)
304		if err != nil {
305			return "", fmt.Errorf("resolving git root: %w", err)
306		}
307		wtDir := filepath.Join(gitRoot, ".worktrees", fmt.Sprintf("%s-%s", compareID, harnessName))
308		cmd := internalgit.Command(context.Background(), gitRoot, "worktree", "add", "--detach", wtDir, "HEAD")
309		if out, err := cmd.CombinedOutput(); err != nil {
310			return "", fmt.Errorf("git worktree add: %s\n%s", err, string(out))
311		}
312		return wtDir, nil
313	}
314	
315	func resolveGitRoot(dir string) (string, error) {
316		cmd := internalgit.Command(context.Background(), dir, "rev-parse", "--show-toplevel")
317		out, err := cmd.Output()
318		if err != nil {
319			return "", fmt.Errorf("not a git repository: %s", dir)
320		}
321		return strings.TrimSpace(string(out)), nil
322	}
323	
324	func captureGitDiff(worktreePath string) string {
325		cmd := internalgit.Command(context.Background(), worktreePath, "diff", "HEAD")
326		out, err := cmd.Output()
327		if err != nil {
328			return ""
329		}
330		diff := string(out)
331	
332		cmd3 := internalgit.Command(context.Background(), worktreePath, "ls-files", "--others", "--exclude-standard")
333		untrackedOut, _ := cmd3.Output()
334		untracked := strings.TrimSpace(string(untrackedOut))
335		if untracked != "" {
336			for _, f := range strings.Split(untracked, "\n") {
337				f = strings.TrimSpace(f)
338				if f == "" {
339					continue
340				}
341				content, err := os.ReadFile(filepath.Join(worktreePath, f))
342				if err != nil {
343					continue
344				}
345				diff += fmt.Sprintf("\n--- /dev/null\n+++ b/%s\n@@ -0,0 +1 @@\n", f)
346				for _, line := range strings.Split(string(content), "\n") {
347					if line != "" || len(content) > 0 {
348						diff += "+" + line + "\n"
349					}
350				}
351			}
352		}
353		return strings.TrimSpace(diff)
354	}
