392	// QuorumRuntime is the SD-024 successor to QuorumOptions for the
393	// `ddx agent run --quorum` dispatch path. Durable knobs (Model,
394	// Effort, Permissions, Timeout) are stripped — they live on
395	// config.ResolvedConfig and are passed via RunQuorumWithConfigViaService's
396	// rcfg argument. Only non-serializable plumbing and per-invocation
397	// runtime intent remain.
398	//
399	// See SD-024 / TD-024 §Runtime structs and §Stage 2 QuorumOptions
400	// migration.
401	type QuorumRuntime struct {
402		AgentRunRuntime
403		Harnesses []string
404		Strategy  string
405		Threshold int
406	}
407	
408	// RunQuorumWithConfig is the SD-024 successor to RunQuorumWith. It
409	// accepts a sealed ResolvedConfig (durable knobs) and a QuorumRuntime
410	// (plumbing + per-invocation intent), assembles an equivalent
411	// QuorumOptions, and delegates to RunQuorumWith.
412	func RunQuorumWithConfig(run RunFunc, rcfg config.ResolvedConfig, runtime QuorumRuntime) ([]*Result, error) {
413		var opts QuorumOptions
414		opts.RunOptions = RunOptions{
415			Prompt:       runtime.Prompt,
416			PromptFile:   runtime.PromptFile,
417			PromptSource: runtime.PromptSource,
418			Correlation:  runtime.Correlation,
419			Model:        rcfg.Model(),
420			Effort:       rcfg.Effort(),
421			Timeout:      rcfg.Timeout(),
422			WorkDir:      runtime.WorkDir,
423			Permissions:  rcfg.Permissions(),
424		}
425		opts.Harnesses = runtime.Harnesses
426		opts.Strategy = runtime.Strategy
427		opts.Threshold = runtime.Threshold
428		return RunQuorumWith(run, opts)
429	}
