487	func RunQuorumWithAgent(ctx context.Context, agent agentlib.DdxAgent, workDir string, opts QuorumOptions) ([]*Result, error) {
488		run := func(runOpts RunOptions) (*Result, error) {
489			return RunViaServiceWith(ctx, agent, workDir, runOpts)
490		}
491		return RunQuorumWith(run, opts)
