494	// QuorumMet returns true if enough results succeeded.
495	func QuorumMet(strategy string, threshold int, results []*Result) bool {
496		total := len(results)
497		eff := effectiveThreshold(strategy, threshold, total)
498		successes := 0
499		for _, r := range results {
500			if r != nil && r.ExitCode == 0 {
501				successes++
502			}
503		}
504		return successes >= eff
505	}
506	
507	func effectiveThreshold(strategy string, threshold, total int) int {
508		switch strategy {
509		case "any":
510			return 1
511		case "majority":
512			return (total / 2) + 1
513		case "unanimous":
514			return total
515		default:
516			if threshold > 0 {
517				return threshold
518			}
519			return 1
520		}
521	}
