656	// RunBenchmarkWith executes all prompts in a suite against all arms via the
657	// runCompare closure. Production callers should use RunBenchmarkViaService.
658	func RunBenchmarkWith(runCompare func(CompareOptions) (*ComparisonRecord, error), suite *BenchmarkSuite) (*BenchmarkResult, error) {
659		result := &BenchmarkResult{
660			Suite:     suite.Name,
661			Version:   suite.Version,
662			Timestamp: time.Now().UTC(),
663			Arms:      suite.Arms,
664		}
665	
666		var timeout time.Duration
667		if suite.Timeout != "" {
668			var err error
669			timeout, err = time.ParseDuration(suite.Timeout)
670			if err != nil {
671				return nil, fmt.Errorf("invalid timeout %q: %w", suite.Timeout, err)
672			}
673		}
674	
675		for _, prompt := range suite.Prompts {
676			promptText := prompt.Prompt
677			if promptText == "" && prompt.PromptFile != "" {
678				data, err := readPromptFileBounded(prompt.PromptFile)
679				if err != nil {
680					return nil, fmt.Errorf("reading prompt file %s: %w", prompt.PromptFile, err)
681				}
682				promptText = string(data)
683			}
684	
685			baseOpts := RunOptions{
686				Prompt:  promptText,
687				Timeout: timeout,
688			}
689	
690			compareOpts := BenchmarkArmsToCompare(suite.Arms, baseOpts)
691			compareOpts.Sandbox = suite.Sandbox
692			compareOpts.PostRun = suite.PostRun
693	
694			record, err := runCompare(compareOpts)
695			if err != nil {
696				return nil, fmt.Errorf("prompt %s: %w", prompt.ID, err)
697			}
698	
699			result.Comparisons = append(result.Comparisons, *record)
700		}
701	
702		result.Summary = benchSummarize(result)
703		return result, nil
704	}
