706	// RunBenchmarkViaService is the production replacement for Runner.RunBenchmark.
707	func RunBenchmarkViaService(ctx context.Context, workDir string, suite *BenchmarkSuite) (*BenchmarkResult, error) {
708		return RunBenchmarkWith(func(opts CompareOptions) (*ComparisonRecord, error) {
709			return RunCompareViaService(ctx, workDir, opts)
710		}, suite)
711	}
