713	// RunBenchmarkWithAgent calls RunBenchmarkViaService using a pre-built DdxAgent.
714	func RunBenchmarkWithAgent(ctx context.Context, agent agentlib.DdxAgent, workDir string, suite *BenchmarkSuite) (*BenchmarkResult, error) {
715		return RunBenchmarkWith(func(opts CompareOptions) (*ComparisonRecord, error) {
716			return RunCompareWithAgent(ctx, agent, workDir, opts)
717		}, suite)
