719	
720	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
721		summary := BenchmarkSummary{
722			TotalPrompts: len(result.Comparisons),
723		}
724		armStats := make(map[string]*BenchmarkArmSummary)
725		armOrder := make([]string, len(result.Arms))
726		for i, arm := range result.Arms {
727			label := arm.Label
728			armOrder[i] = label
729			armStats[label] = &BenchmarkArmSummary{Label: label}
730		}
731		for _, cmp := range result.Comparisons {
732			for _, arm := range cmp.Arms {
733				stats, ok := armStats[arm.Harness]
734				if !ok {
735					continue
736				}
737				if arm.ExitCode == 0 {
738					stats.Completed++
739				} else {
740					stats.Failed++
741				}
742				stats.TotalTokens += arm.Tokens
743				stats.TotalCostUSD += arm.CostUSD
744				stats.AvgDurationMS += arm.DurationMS
745			}
746		}
747		for _, label := range armOrder {
748			stats := armStats[label]
749			total := stats.Completed + stats.Failed
750			if total > 0 {
751				stats.AvgDurationMS = stats.AvgDurationMS / total
752			}
753			summary.Arms = append(summary.Arms, *stats)
754		}
755		return summary
756	}
