71	// RunWithConfigViaService is the SD-024 successor to RunViaService. It
72	// takes a sealed ResolvedConfig (durable knobs) and an AgentRunRuntime
73	// (per-invocation plumbing/intent), assembles an equivalent RunOptions,
74	// and delegates to RunViaService. Production callers under
75	// `ddx agent run` use this path so config.LoadAndResolve drives every
76	// durable knob exactly once at the dispatch site.
77	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
78		sessionLogDir := runtime.SessionLogDirOverride
79		if sessionLogDir == "" {
80			sessionLogDir = rcfg.SessionLogDir()
81		}
82		opts := RunOptions{
83			Context:       ctx,
84			Harness:       rcfg.Harness(),
85			Prompt:        runtime.Prompt,
86			PromptFile:    runtime.PromptFile,
87			PromptSource:  runtime.PromptSource,
88			Correlation:   runtime.Correlation,
89			Model:         rcfg.Model(),
90			Provider:      rcfg.Provider(),
91			ModelRef:      rcfg.ModelRef(),
92			Effort:        rcfg.Effort(),
93			Timeout:       rcfg.Timeout(),
94			WallClock:     rcfg.WallClock(),
95			WorkDir:       runtime.WorkDir,
96			Permissions:   rcfg.Permissions(),
97			SessionLogDir: sessionLogDir,
98		}
99		return RunViaService(ctx, workDir, opts)
100	}
